// Fetch Pinecone index stats and build namespace list
const PINECONE_HOST = '{{ $env.PINECONE_HOST }}';
const PINECONE_KEY = '{{ $env.PINECONE_API_KEY }}';

const resp = await fetch(`${PINECONE_HOST}/describe_index_stats`, {
  method: 'POST',
  headers: { 'Api-Key': PINECONE_KEY, 'Content-Type': 'application/json' },
  body: '{}',
});
if (!resp.ok) throw new Error(`Pinecone describe_index_stats failed: ${resp.status}`);
const stats = await resp.json();

// Namespace → collection mapping
const namespaceMap = {
  'gda-documents': 'gda-documents',
  '': 'ai-agent-attachments',
};

const items = [];
for (const [ns, info] of Object.entries(stats.namespaces || {})) {
  let collection = namespaceMap[ns];
  if (collection === undefined) {
    collection = ns; // fallback: use namespace name as collection
    console.warn(`Unmapped namespace '${ns}' → using as collection name`);
  }
  items.push({
    json: {
      namespace: ns,
      collection,
      expected_count: info.vectorCount,
      index_host: PINECONE_HOST,
    },
  });
}

return items;

// Backfill one namespace from Pinecone → pgvector
const PINECONE_HOST = '{{ $env.PINECONE_HOST }}';
const PINECONE_KEY = '{{ $env.PINECONE_API_KEY }}';
const GDA_KEY = '{{ $env.GDA_WEBHOOK_KEY }}';
const BACKEND_URL = 'http://gda-backend:3001';

const item = $input.first().json;
const ns = item.namespace;
const collection = item.collection;
const expectedCount = item.expected_count;

let totalFetched = 0;
let totalUpserted = 0;
let errors = [];
let batchNum = 0;
let paginationToken = null;

// DRY_RUN limit: set to 0 for full run, or N for dry-run
const DRY_RUN_LIMIT = 10;

do {
  // Step 1: List vector IDs (paginated, 100 per page)
  let listUrl = `${PINECONE_HOST}/vectors/list?namespace=${encodeURIComponent(ns)}&limit=100`;
  if (paginationToken) listUrl += `&paginationToken=${encodeURIComponent(paginationToken)}`;

  const listResp = await fetch(listUrl, {
    method: 'GET',
    headers: { 'Api-Key': PINECONE_KEY },
  });
  if (!listResp.ok) {
    errors.push(`List failed for ns=${ns}: ${listResp.status}`);
    break;
  }
  const listData = await listResp.json();
  const vectorIds = (listData.vectors || []).map(v => v.id);
  paginationToken = listData.pagination?.next || null;

  if (vectorIds.length === 0) break;

  // Step 2: Fetch full vectors (values + metadata)
  const fetchResp = await fetch(`${PINECONE_HOST}/vectors/fetch`, {
    method: 'POST',
    headers: { 'Api-Key': PINECONE_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({ ids: vectorIds, namespace: ns }),
  });
  if (!fetchResp.ok) {
    errors.push(`Fetch failed for ns=${ns} batch ${batchNum}: ${fetchResp.status}`);
    break;
  }
  const fetchData = await fetchResp.json();
  const vectors = fetchData.vectors || {};

  // Step 3: Transform to VectorItem shape
  const upsertItems = [];
  for (const [id, vec] of Object.entries(vectors)) {
    const meta = vec.metadata || {};
    upsertItems.push({
      id,
      document_id: meta.document_id || null,
      chunk_index: meta.chunk_index || 0,
      chunk_text: meta.text || meta.chunk_text || '',
      page_number: meta.page || meta.page_number || null,
      section_title: meta.section_title || meta.heading || null,
      embedding: vec.values,
      collection,
      metadata: meta,
    });
  }

  if (upsertItems.length === 0) continue;

  // Step 4: POST to vector-upsert
  const upsertResp = await fetch(`${BACKEND_URL}/api/internal/vector-upsert`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-gda-key': GDA_KEY,
    },
    body: JSON.stringify({ collection, items: upsertItems }),
  });

  if (upsertResp.ok) {
    totalUpserted += upsertItems.length;
  } else {
    const errText = await upsertResp.text();
    errors.push(`Upsert failed batch ${batchNum}: ${upsertResp.status} ${errText}`);
  }

  totalFetched += vectorIds.length;
  batchNum++;

  if (DRY_RUN_LIMIT > 0 && totalFetched >= DRY_RUN_LIMIT) {
    paginationToken = null; // stop early
  }
} while (paginationToken);

return [{
  json: {
    namespace: ns,
    collection,
    expected_count: expectedCount,
    total_fetched: totalFetched,
    total_upserted: totalUpserted,
    batches: batchNum,
    errors,
    status: errors.length === 0 ? 'success' : 'partial',
  },
}];

// Query pgvector for final count per collection
const GDA_KEY = '{{ $env.GDA_WEBHOOK_KEY }}';
const BACKEND_URL = 'http://gda-backend:3001';
const item = $input.first().json;

// Use the vector-query endpoint to verify count (query with zero vector)
const dummyEmbedding = new Array(1536).fill(0.01);
const resp = await fetch(`${BACKEND_URL}/api/internal/vector-query`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-gda-key': GDA_KEY },
  body: JSON.stringify({ collection: item.collection, embedding: dummyEmbedding, topK: 1 }),
});
const data = resp.ok ? await resp.json() : { error: await resp.text() };

return [{
  json: {
    ...item,
    pgvector_query_check: resp.ok ? 'ok' : 'error',
    sample_result: data?.data?.results?.[0]?.id || 'none',
  },
}];
